const raw = $input.item.json;

let sugestao;
try {
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const clean = text.replace(/```json|```/g, '').trim();
  sugestao = typeof raw === 'object' ? raw : JSON.parse(clean);
} catch(e) { sugestao = raw; }

const filtros = $('Preparar Filtros').item.json;

// Build Metacritic-style slug: lowercase, spaces→hyphens, remove special chars
const nome = sugestao.nome || '';
const slug = nome
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-');

return [{ json: {
  email: filtros.email,
  genero: filtros.genero,
  genre_id: filtros.genre_id,
  runtime_max: filtros.runtime_max,
  temp_max: filtros.temp_max,
  nome_sugerido: nome,
  slug_metacritic: slug,
  por_que_assistir: sugestao.por_que_assistir || ''
}}];

const html = $input.item.json.data || $input.item.json || '';
const anterior = $('Extrair Nome Sugerido').item.json;

// --- Extract Metascore (critic score 0-100) ---
// Metacritic embeds scores in JSON-LD and also in data attributes
let metascore = null;
let userscore = null;
let descricao = '';
let genres = [];
let premiere = '';
let metacritic_url = `https://www.metacritic.com/tv/${anterior.slug_metacritic}/`;

const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

// Metascore — look for scoreValue or score-number patterns
const metaMatch = htmlStr.match(/\"metaScore\":\s*\"?(\d+)\"?/)
  || htmlStr.match(/c-siteReviewScore[^>]*>\s*<span[^>]*>(\d+)<\/span>/)
  || htmlStr.match(/Metascore[^\d]*(\d{2,3})/i)
  || htmlStr.match(/\"score\":\s*\"?(\d{2,3})\"?.*?critic/i);
if (metaMatch) metascore = parseInt(metaMatch[1]);

// User score (0-10 scale)
const userMatch = htmlStr.match(/\"userScore\":\s*\"?([\d.]+)\"?/)
  || htmlStr.match(/User Score[^\d]*([\d.]+)/i);
if (userMatch) userscore = parseFloat(userMatch[1]);

// Description from JSON-LD or og:description
const descMatch = htmlStr.match(/\"description\":\s*\"([^\"]{20,500})\"/)
  || htmlStr.match(/content=\"([^\"]{30,400})\"[^>]*name=\"description\"/i)
  || htmlStr.match(/og:description.*?content=\"([^\"]{20,400})\"/i);
if (descMatch) descricao = descMatch[1].replace(/\\n/g, ' ').replace(/\\u[0-9a-f]{4}/gi, '').trim();

// Premiere / first air date
const premMatch = htmlStr.match(/\"datePublished\":\s*\"([\d-]+)\"/);
if (premMatch) premiere = premMatch[1].substring(0, 4);

// Genres from JSON-LD
const genreMatch = htmlStr.match(/\"genre\":\s*(\[[^\]]+\])/i);
if (genreMatch) {
  try { genres = JSON.parse(genreMatch[1]); } catch(e) {}
}

// Score label for email display
let scoreLabel = 'N/A';
let scoreColor = '#888';
if (metascore !== null) {
  scoreLabel = String(metascore);
  scoreColor = metascore >= 61 ? '#6c3' : metascore >= 40 ? '#fc3' : '#f33';
}

return [{ json: {
  email: anterior.email,
  genero: anterior.genero,
  nome: anterior.nome_sugerido,
  ano: premiere || '—',
  metascore: metascore !== null ? metascore : '—',
  userscore: userscore !== null ? userscore : '—',
  score_label: scoreLabel,
  score_color: scoreColor,
  descricao: descricao || `Série de ${anterior.genero} recomendada pelo nosso sistema.`,
  genres: genres.join(', ') || anterior.genero,
  por_que_assistir: anterior.por_que_assistir,
  metacritic_url,
  slug: anterior.slug_metacritic
}}];
